        "distractors": [
          "Picts",
          "Scots"
        ]
      },
      {
        "question": "What happened after the Romans ruled Britain?",
        "hint": "They did not stay in Britain.",
        "questionType": "multiple-choice",
        "answers": [
          "They left Britain."
        ],
        "distractors": [
          "They built a new country.",
          "They changed its name."
        ]
      },
      {
        "question": "What do we call a group of people like the Romans, Picts or Scots?",
        "hint": "They are groups of people with their own names.",
        "questionType": "multiple-choice",
        "answers": [
          "a people"
        ],
        "distractors": [
          "a building",
          "a weather"
        ]
      },
      {
        "question": "If people live in different parts of a country, what can this mean?",
        "hint": "Think about where people choose or are able to live.",
        "questionType": "multiple-choice",
        "answers": [
          "They live in different places."
        ],
        "distractors": [
          "They all live together.",
          "They never move home."
